var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"마에스트로……? 갑자기 나타나서 무슨 소리야?","JPN":"マエストロ……？　いきなり出てきてなんのこと？","ENG":"Maestra...? What are you talking about? You just appear all of a sudden and say all these weird things?","TWN":"指揮家……？沒頭沒尾地在胡說什麼？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그것은 역병에 취해 만행을 저지른 그림자의 이름.","JPN":"それは疫病に酔い、蛮行を犯したシャドウの名。","ENG":"It is the name of the Shadow that has committed several atrocities under the influence of the plague.","TWN":"那是沉浸在瘟疫裡肆意妄為的暗影的名字。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그리고 이 세계의 안녕을 위해 축출되어야 할 존재다.","JPN":"そしてこの世の安寧のため、追い出さなければならない存在である。","ENG":"She must be expunged for the sake of this world.","TWN":"而為了這個世界的和平，勢必得將她驅逐。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……저기, 좀 알아듣게 말해 줄래?","JPN":"……あの、ちょっとわかるように説明してくれない？","ENG":"...Excuse me, could you say something I’d understand?","TWN":"……那個，你可以說白話文嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이해할 필요는 없다, 여인이여.","JPN":"理解する必要はなかろう、女よ。","ENG":"Your understanding is unnecessary.","TWN":"女人，你聽不懂也無所謂。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"시험을 치른 뒤에 이제까지의 무례는 목숨을 다해 사죄하도록 하마.","JPN":"試練が終わった後、これまでの無礼は命をかけてでも謝罪しよう。","ENG":"If you prove true upon examination, I shall do my utmost to apologize for my rudeness.","TWN":"等測試開始後，至今對你的無禮，我會用性命來賠罪。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그러니 지금은…… 의연히 안식을 받아들여라.","JPN":"だから今は……毅然と安息を受け入れろ。","ENG":"So for now... Embrace eternal rest with honor.","TWN":"所以……現在你就進入安息吧。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"TWN":"　"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ugh!","TWN":"唔……！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"도끼로 건물을 무너뜨려……? 저 갑옷, 카운터가 맞긴 한 건가?","JPN":"斧で建物を崩した……？　あの鎧、本当にカウンターなの？","ENG":"Taking out a building with just an axe...? Is that armor a Counter?","TWN":"竟然用那把斧頭就毀掉整棟建築……？那個鎧甲是制裁者嗎？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"지, 집이 통째로 무너졌어!","JPN":"い、家が丸ごと崩れた！","ENG":"T-The whole house collapsed!","TWN":"整…整棟都塌了！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체인가?! 아니면 반군……?","JPN":"侵食体！？　それとも反乱軍……？","ENG":"Is it a Corrupted Object?! Or a rebel...?","TWN":"是侵蝕體嗎？！還是叛軍……？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"지금 그게 중요한 게 아니잖아! 어서 신고해!","JPN":"今はそれどころじゃないだろ！　早く通報しろ！","ENG":"That’s not important right now! We’ve got to call the cops!","TWN":"管他是誰！先報警再說啦！！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"보다 절박하여야 본색을 드러낼 텐가. 마에스트로.","JPN":"もっと切実ではないと本性を現わさないのか。マエストロ。","ENG":"Was that not enough? Will you reveal your true colors if I make you even more desperate, Maestra?","TWN":"看來必須再急迫一點，你才會露出真面目是嗎，指揮家？"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"누군지도 모를 놈이랑 착각하는 건 적당히 해!!","JPN":"誰だかわからない奴と勘違いするのはいい加減にして！！","ENG":"I don’t know who the hell you’re talking about, but I’m not her!!","TWN":"你不要再把我誤認成某個我不認識的傢伙囉！！"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……몽타뉴는 네게 안식을 선사할 기회가 있었음에도 주저했다고 하였다.","JPN":"……モンターニュは貴様に安息を与える機会があったにもかかわらず、ためらったのだと言った。","ENG":"...Montagne said she hesitated even though she had an opportunity to put you to rest.","TWN":"……蒙塔妮說她曾經有機會讓你進入安息，但她當時猶豫了。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"일전에 조우하였을 때, 지극히 인간다운 면모를 보았다고 하더군.","JPN":"この前遭遇した時、限りなく人間的な面を見たとも言っていたな。","ENG":"When she met you the other day, she said you showed a very human side.","TWN":"因為之前交手時，她有見到你人性化的一面。"},"stage":{"bg":"GRONIA_STREET","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};